"use client";

/**
 * Admin user table — cold-start build on @gunjo/ui@0.0.1-alpha.2.
 *
 * Discovery notes (black-box: typed barrel in node_modules + gunjo.jp docs):
 *
 *  - Component chosen: `DataTable` (display/DataTable). It is a TanStack-Table
 *    (@tanstack/react-table v8) wrapper that ships sorting, pagination AND a
 *    single-column text filter built in. The plain `Table` family is just dumb
 *    primitives (no logic), and `Pagination` is presentation-only (renders <a>s,
 *    no state). Since this task needs sort + paginate + filter, DataTable does
 *    the heavy lifting with the least glue — the right tool here.
 *
 *  - Columns use TanStack `ColumnDef<User>[]`. `accessorKey` feeds the value
 *    used for filtering/sorting; `header` is a string/node; `cell` gets
 *    `{ row }` and you read `row.original` / `row.getValue(id)`. Sorting is ON
 *    by default for accessor columns — `enableSorting: false` opts a column out.
 *
 *  - Built-in text filter: pass `filter={{ columnId, placeholder }}`. It filters
 *    ONE column only (here: `name`). There is no built-in dropdown/faceted
 *    filter, so the STATUS dropdown is done OUTSIDE DataTable: a `<Select>` whose
 *    value pre-filters the `data` array via useMemo before it reaches DataTable.
 *
 *  - `Badge` variants are exactly: default | secondary | destructive | outline.
 *    No semantic success/warning, so statuses are mapped onto those four.
 *
 *  - `Select` is a thin native <select> wrapper: value / onChange / <option>
 *    children. Controlled normally.
 *
 *  - No provider/wrapper was required. DataTable renders Radix Tooltips on the
 *    sort headers + pagination buttons, but gunjo's Tooltip self-wraps its
 *    provider (no <TooltipProvider> needed). No SSR/prerender crash — though the
 *    components are "use client", so this page is a client component.
 */

import * as React from "react";
import {
  Badge,
  type BadgeProps,
  Container,
  DataTable,
  Select,
} from "@gunjo/ui";
// FRICTION: @gunjo/ui does NOT re-export TanStack's ColumnDef from its barrel
// (it only ships the DataTable component). A cold adopter must reach into
// @tanstack/react-table directly — which is a *transitive* dep here (not in
// this app's package.json), so this import only resolves thanks to npm
// hoisting. The docs list `columns: ColumnDef<TData, TValue>[]` but never say
// where ColumnDef comes from.
import type { ColumnDef } from "@tanstack/react-table";

type Status = "Active" | "Invited" | "Suspended";
type Role = "Owner" | "Admin" | "Editor" | "Viewer";

type User = {
  id: string;
  name: string;
  email: string;
  role: Role;
  status: Status;
  joined: string; // ISO date
  mrr: number; // monthly recurring revenue, USD
};

const USERS: User[] = [
  { id: "u01", name: "田中 葵", email: "aoi.tanaka@example.com", role: "Owner", status: "Active", joined: "2023-01-12", mrr: 48000 },
  { id: "u02", name: "佐藤 大輔", email: "daisuke.sato@example.com", role: "Admin", status: "Active", joined: "2023-03-04", mrr: 32000 },
  { id: "u03", name: "鈴木 美咲", email: "misaki.suzuki@example.com", role: "Editor", status: "Invited", joined: "2024-06-22", mrr: 0 },
  { id: "u04", name: "高橋 健", email: "ken.takahashi@example.com", role: "Viewer", status: "Suspended", joined: "2022-11-18", mrr: 0 },
  { id: "u05", name: "山本 玲奈", email: "rena.yamamoto@example.com", role: "Editor", status: "Active", joined: "2023-08-30", mrr: 29000 },
  { id: "u06", name: "中村 翔太", email: "shota.nakamura@example.com", role: "Admin", status: "Active", joined: "2024-02-09", mrr: 41000 },
  { id: "u07", name: "小林 花", email: "hana.kobayashi@example.com", role: "Viewer", status: "Invited", joined: "2025-01-15", mrr: 0 },
  { id: "u08", name: "加藤 直樹", email: "naoki.kato@example.com", role: "Editor", status: "Active", joined: "2023-05-27", mrr: 25000 },
  { id: "u09", name: "佐々木 優", email: "yu.sasaki@example.com", role: "Admin", status: "Suspended", joined: "2022-09-03", mrr: 0 },
  { id: "u10", name: "渡辺 美穂", email: "miho.watanabe@example.com", role: "Viewer", status: "Active", joined: "2024-10-11", mrr: 18000 },
  { id: "u11", name: "伊藤 大和", email: "yamato.ito@example.com", role: "Editor", status: "Active", joined: "2023-12-01", mrr: 30000 },
  { id: "u12", name: "松本 さくら", email: "sakura.matsumoto@example.com", role: "Viewer", status: "Invited", joined: "2025-03-19", mrr: 0 },
  { id: "u13", name: "森 健司", email: "kenji.mori@example.com", role: "Admin", status: "Active", joined: "2022-07-14", mrr: 52000 },
  { id: "u14", name: "井上 恵美", email: "emi.inoue@example.com", role: "Editor", status: "Suspended", joined: "2023-02-28", mrr: 0 },
  { id: "u15", name: "木村 拓海", email: "takumi.kimura@example.com", role: "Viewer", status: "Active", joined: "2024-04-07", mrr: 15000 },
  { id: "u16", name: "林 千尋", email: "chihiro.hayashi@example.com", role: "Owner", status: "Active", joined: "2021-12-20", mrr: 60000 },
];

const STATUSES: Status[] = ["Active", "Invited", "Suspended"];

const statusVariant: Record<Status, NonNullable<BadgeProps["variant"]>> = {
  Active: "default",
  Invited: "secondary",
  Suspended: "destructive",
};

const statusLabel: Record<Status, string> = {
  Active: "有効",
  Invited: "招待中",
  Suspended: "停止中",
};

const roleLabel: Record<Role, string> = {
  Owner: "オーナー",
  Admin: "管理者",
  Editor: "編集者",
  Viewer: "閲覧者",
};

const usd = (n: number) =>
  new Intl.NumberFormat("ja-JP", {
    style: "currency",
    currency: "JPY",
    maximumFractionDigits: 0,
  }).format(n);

const dateFmt = (iso: string) =>
  new Intl.DateTimeFormat("ja-JP", {
    year: "numeric",
    month: "short",
    day: "numeric",
  }).format(new Date(iso));

const columns: ColumnDef<User>[] = [
  {
    accessorKey: "name",
    header: "名前",
    cell: ({ row }) => {
      const user = row.original;
      return (
        <div className="flex flex-col">
          <span className="font-medium text-foreground">{user.name}</span>
          <span className="text-xs text-muted-foreground">{user.email}</span>
        </div>
      );
    },
  },
  {
    accessorKey: "role",
    header: "権限",
    cell: ({ row }) => (
      <span className="text-sm">{roleLabel[row.getValue("role") as Role]}</span>
    ),
  },
  {
    accessorKey: "status",
    header: "ステータス",
    enableSorting: false,
    cell: ({ row }) => {
      const status = row.getValue("status") as Status;
      return <Badge variant={statusVariant[status]}>{statusLabel[status]}</Badge>;
    },
  },
  {
    accessorKey: "joined",
    header: "登録日",
    cell: ({ row }) => (
      <span className="whitespace-nowrap text-sm text-muted-foreground">
        {dateFmt(row.getValue("joined"))}
      </span>
    ),
  },
  {
    accessorKey: "mrr",
    header: "月次収益",
    cell: ({ row }) => (
      <span className="tabular-nums">{usd(row.getValue("mrr"))}</span>
    ),
  },
];

export default function UsersPage() {
  const [statusFilter, setStatusFilter] = React.useState<"all" | Status>("all");

  // The DataTable text filter handles `name`. The status DROPDOWN filter is
  // applied here, before the data reaches DataTable.
  const filteredData = React.useMemo(
    () =>
      statusFilter === "all"
        ? USERS
        : USERS.filter((u) => u.status === statusFilter),
    [statusFilter]
  );

  return (
    <main className="min-h-screen bg-background py-12 text-foreground">
      <Container size="lg" className="flex flex-col gap-6">
        <header className="flex flex-col gap-1.5">
          <h1 className="text-2xl font-semibold tracking-tight">メンバー</h1>
          <p className="text-sm text-muted-foreground">
            ワークスペースのアクセスを管理します。名前で検索、ステータスで絞り込み、
            任意の列で並べ替え、ページ送りで一覧を閲覧——すべて @gunjo/ui の
            DataTable で実現しています。
          </p>
        </header>

        {/* Status dropdown filter — sits above DataTable's own text filter. */}
        <div className="flex flex-col gap-1.5 sm:max-w-xs">
          <label
            htmlFor="status-filter"
            className="text-sm font-medium text-foreground"
          >
            ステータス
          </label>
          <Select
            id="status-filter"
            value={statusFilter}
            onChange={(e) =>
              setStatusFilter(e.target.value as "all" | Status)
            }
          >
            <option value="all">すべてのステータス</option>
            {STATUSES.map((s) => (
              <option key={s} value={s}>
                {statusLabel[s]}
              </option>
            ))}
          </Select>
        </div>

        <DataTable
          columns={columns}
          data={filteredData}
          filter={{ columnId: "name", placeholder: "名前で検索…" }}
          labels={{ noResults: "該当するユーザーがいません" }}
          pageSize={5}
          pageSizeOptions={[5, 10, 25]}
        />
      </Container>
    </main>
  );
}
